mapper.select:
select concat(COMPKEY, WAREKEY, PASTRKY) as ROWKEY , COMPKEY , WAREKEY , PASTRKY , PASTRNM , PADELYN , date_format(CREDATE, '%Y-%m-%d') as CREDATE, date_format(CRETIME, '%Y-%m-%d') as CRETIME, fn_sy_usernam(COMPKEY,CREUSER) as CREUSER , date_format(LMODATE, '%Y-%m-%d') as LMODATE, date_format(LMOTIME, '%Y-%m-%d') as LMOTIME, fn_sy_usernam(COMPKEY,LMOUSER) as LMOUSER , INDIBZL, INDIARC, UPDTCHK from WPASHD where 1=1 and COMPKEY = #{userData.compkey}
and WAREKEY = #{warekey}
and PASTRKY = #{pastrky}
and upper(PASTRNM) like concat('%', upper(#{pastrnm}), '%')
order by COMPKEY, WAREKEY, PASTRKY

mapper.insert:

insert 
  into WPASHD( COMPKEY, WAREKEY, PASTRKY, PASTRNM, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER )
values ( #{compkey}, #{warekey}, upper(#{pastrky}), #{pastrnm}
     , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{creuser}
     , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{lmouser} )

mapper.update:

update WPASHD 
   set PASTRNM = #{pastrnm}
   	 , PADELYN = #{padelyn}
     , LMODATE = to_char(NOW() ,'YYYYMMDD')
     , LMOTIME = to_char(NOW() ,'hh24miss')
     , LMOUSER = #{lmouser}
 where COMPKEY = #{compkey}
   and WAREKEY = #{warekey}
   and PASTRKY = #{pastrky}
   and UPDTCHK = #{updtchk}

mapper.insert:

insert
  into WPASIT ( COMPKEY, WAREKEY, PASTRKY, PASTRIT, PASTROD, PASTRMD
  			  , RCVLOCA, RCVZONE, RCVSABC, PAWLOCA, PAWZONE, SCHMETH
  			  , SCHSFNO, SCHEFNO, SCHMXOP, SCHLROP
			  , CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER )
values

( #{item.compkey}, #{item.warekey}, #{item.pastrky}, fn_wm_pastrit(#{item.compkey},#{item.warekey}, #{item.pastrky}), #{item.pastrod}, #{item.pastrmd}
, #{item.rcvloca}, #{item.rcvzone}, #{item.rcvsabc}, #{item.pawloca}, #{item.pawzone}, #{item.schmeth}
, #{item.schsfno}, #{item.schefno}, #{item.schmxop}, #{item.schlrop}
, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract} )

