mapper.select:

	select PASTRKY as combovl
		 , PASTRNM as combonm
	  from WPASHD
  	 where 1=1 

  	   and COMPKEY = #{compkey}


	   and WAREKEY = #{warekey}


	   and PASTRKY = #{pastrky}


	   and PADELYN = #{padelyn}

  	 group by PASTRKY, PASTRNM
