select concat(COMPKEY, WAREKEY, PAORDIT) as ROWKEY , COMPKEY, WAREKEY, PAORDIT, PAORDOD, PASTRKY, DOCCATE, DOCTYPE, OWNERKY , SKUMKEY, VENDKEY, CARRKEY, SKUWABC, BRANDCD, SKUGR01, SKUGR02, SKUGR03 , SKUGR04, SKUGR05 ,PADELYN , date_format(CREDATE, '%Y-%m-%d') as CREDATE, date_format(CRETIME, '%Y-%m-%d') as CRETIME, fn_sy_usernam(COMPKEY, CREUSER) as CREUSER , date_format(LMODATE, '%Y-%m-%d') as LMODATE, date_format(LMOTIME, '%Y-%m-%d') as LMOTIME, fn_sy_usernam(COMPKEY, LMOUSER) as LMOUSER , INDIBZL, INDIARC, UPDTCHK from WPAORD where 1=1 and COMPKEY = #{userData.compkey}
and WAREKEY = #{warekey}
order by COMPKEY, WAREKEY, PAORDIT

insert.foreach:
	insert
	  into WPAORD ( 
	  	   COMPKEY
	  	 , WAREKEY
	  	 , PAORDIT
	  	 , PAORDOD
	  	 , PASTRKY
	  	 , DOCCATE

		 , DOCTYPE


		 , OWNERKY


		 , SKUMKEY


		 , VENDKEY


		 , SKUWABC


		 , BRANDCD


		 , SKUGR02


		 , SKUGR03


		 , SKUGR04


		 , PADELYN

	  	, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER )
   values ( 
		  #{item.compkey}
		, #{item.warekey}
		, ( select IFNULL(MAX(PAORDIT)+1,1) 
		      from WPAORD W
		     where W.COMPKEY = #{item.compkey}
		       and W.WAREKEY = #{item.warekey} )
		, #{item.paordod}
		, #{item.pastrky}
		, #{item.doccate}

	 	, #{item.doctype}


		, #{item.ownerky}


		, #{item.skumkey}


		, #{item.vendkey}


		, #{item.skuwabc}


		, #{item.brandcd}


		, #{item.skugr02}


		, #{item.skugr03}


		, #{item.skugr04}


		, #{item.padelyn}

		, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
		, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract} )

delete.foreach:
delete from WPAORD
 where COMPKEY = #{item.compkey}   
   and WAREKEY = #{item.warekey}
   and PAORDIT = #{item.paordit}
